import{_ as e,o as l,c as d,ae as a}from"./chunks/framework.BEtfQoF7.js";const g=JSON.parse('{"title":"웹에서 작업 예약하기","description":"cron 방식의 반복 주기로 Claude Code 작업을 예약하세요. 클라우드 세션에서 PR 리뷰, 의존성 감사, CI 분류를 자동화할 수 있습니다.","frontmatter":{"title":"웹에서 작업 예약하기","description":"cron 방식의 반복 주기로 Claude Code 작업을 예약하세요. 클라우드 세션에서 PR 리뷰, 의존성 감사, CI 분류를 자동화할 수 있습니다."},"headers":[],"relativePath":"web-scheduled-tasks.md","filePath":"web-scheduled-tasks.md","lastUpdated":1776205703000}'),o={name:"web-scheduled-tasks.md"};function s(r,t,n,c,i,h){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="웹에서-작업-예약하기" tabindex="-1">웹에서 작업 예약하기 <a class="header-anchor" href="#웹에서-작업-예약하기" aria-label="Permalink to &quot;웹에서 작업 예약하기&quot;">​</a></h1><p>예약된 작업은 Anthropic이 관리하는 인프라를 사용해 반복 주기마다 프롬프트를 실행합니다. 내 컴퓨터가 꺼져 있어도 작업은 계속 실행됩니다.</p><p>자동화할 수 있는 반복 작업의 예시입니다:</p><ul><li>매일 아침 열린 풀 리퀘스트 검토</li><li>밤 사이 CI 실패 분석 후 요약 제공</li><li>PR 병합 후 문서 동기화</li><li>매주 의존성 감사 실행</li></ul><p>예약된 작업은 Pro, Max, Team, Enterprise를 포함한 모든 Claude Code 웹 사용자에게 제공됩니다.</p><h2 id="예약-옵션-비교" tabindex="-1">예약 옵션 비교 <a class="header-anchor" href="#예약-옵션-비교" aria-label="Permalink to &quot;예약 옵션 비교&quot;">​</a></h2><p>Claude Code는 반복 작업을 예약하는 세 가지 방법을 제공합니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;"><a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드</a></th><th style="text-align:left;"><a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">데스크탑</a></th><th style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html"><code>/loop</code></a></th></tr></thead><tbody><tr><td style="text-align:left;">실행 위치</td><td style="text-align:left;">Anthropic 클라우드</td><td style="text-align:left;">내 컴퓨터</td><td style="text-align:left;">내 컴퓨터</td></tr><tr><td style="text-align:left;">컴퓨터 켜짐 필요</td><td style="text-align:left;">아니오</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">열린 세션 필요</td><td style="text-align:left;">아니오</td><td style="text-align:left;">아니오</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">재시작 후 지속성</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td><td style="text-align:left;">아니오 (세션 범위)</td></tr><tr><td style="text-align:left;">로컬 파일 접근</td><td style="text-align:left;">아니오 (새로 클론)</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">MCP 서버</td><td style="text-align:left;">작업별로 설정된 커넥터</td><td style="text-align:left;"><a href="/claude-code-docs-ko/mcp.html">설정 파일</a> 및 커넥터</td><td style="text-align:left;">세션에서 상속</td></tr><tr><td style="text-align:left;">권한 프롬프트</td><td style="text-align:left;">아니오 (자율 실행)</td><td style="text-align:left;">작업별로 설정 가능</td><td style="text-align:left;">세션에서 상속</td></tr><tr><td style="text-align:left;">예약 커스터마이즈</td><td style="text-align:left;">CLI에서 <code>/schedule</code> 사용</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">최소 간격</td><td style="text-align:left;">1시간</td><td style="text-align:left;">1분</td><td style="text-align:left;">1분</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>컴퓨터 없이도 안정적으로 실행해야 하는 작업에는 <strong>클라우드 작업</strong>을 사용하세요. 로컬 파일과 도구에 접근해야 할 때는 <strong>데스크탑 작업</strong>을 사용하세요. 세션 중 빠른 폴링에는 **<code>/loop</code>**를 사용하세요.</p></div><h2 id="예약된-작업-만들기" tabindex="-1">예약된 작업 만들기 <a class="header-anchor" href="#예약된-작업-만들기" aria-label="Permalink to &quot;예약된 작업 만들기&quot;">​</a></h2><p>예약된 작업은 세 곳에서 만들 수 있습니다:</p><ul><li><strong>웹</strong>: <a href="https://claude.ai/code/scheduled" target="_blank" rel="noreferrer">claude.ai/code/scheduled</a>에 방문해 <strong>새 예약 작업</strong>을 클릭하세요.</li><li><strong>데스크탑 앱</strong>: <strong>Schedule</strong> 페이지를 열고 <strong>New task</strong>를 클릭한 뒤 <strong>New remote task</strong>를 선택하세요. 자세한 내용은 <a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">데스크탑 예약 작업</a>을 참고하세요.</li><li><strong>CLI</strong>: 아무 세션에서나 <code>/schedule</code>을 실행하세요. Claude가 대화형으로 설정을 안내합니다. <code>/schedule daily PR review at 9am</code>처럼 설명을 직접 전달할 수도 있습니다.</li></ul><p>웹과 데스크탑 진입점은 양식을 열어줍니다. CLI는 안내 대화를 통해 동일한 정보를 수집합니다.</p><p>아래 단계는 웹 인터페이스 사용 방법을 안내합니다.</p><p><strong>1단계: 생성 양식 열기</strong></p><p><a href="https://claude.ai/code/scheduled" target="_blank" rel="noreferrer">claude.ai/code/scheduled</a>에 방문해 <strong>새 예약 작업</strong>을 클릭하세요.</p><p><strong>2단계: 작업 이름 지정 및 프롬프트 작성</strong></p><p>작업에 설명적인 이름을 지정하고 Claude가 매번 실행할 프롬프트를 작성하세요. 프롬프트가 가장 중요한 부분입니다. 작업은 자율적으로 실행되므로 프롬프트는 독립적이어야 하고, 무엇을 해야 하는지와 성공의 기준이 명확해야 합니다.</p><p>프롬프트 입력 영역에는 모델 선택기가 포함되어 있습니다. Claude는 작업의 각 실행에 이 모델을 사용합니다.</p><p><strong>3단계: 저장소 선택</strong></p><p>Claude가 작업할 하나 이상의 GitHub 저장소를 추가하세요. 각 저장소는 실행 시작 시 기본 브랜치에서 클론됩니다. Claude는 변경 사항에 대해 <code>claude/</code> 접두사가 붙은 브랜치를 생성합니다. 모든 브랜치로의 푸시를 허용하려면 해당 저장소에서 <strong>Allow unrestricted branch pushes</strong>를 활성화하세요.</p><p><strong>4단계: 환경 선택</strong></p><p>작업을 위한 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#the-cloud-environment">클라우드 환경</a>을 선택하세요. 환경은 클라우드 세션이 접근할 수 있는 항목을 제어합니다:</p><ul><li><strong>네트워크 접근</strong>: 각 실행 중 사용 가능한 인터넷 접근 수준 설정</li><li><strong>환경 변수</strong>: Claude가 사용할 API 키, 토큰, 또는 기타 시크릿 제공</li><li><strong>설정 스크립트</strong>: 각 세션 시작 전 의존성 설치나 도구 설정 같은 설치 명령 실행</li></ul><p><strong>Default</strong> 환경은 기본으로 제공됩니다. 커스텀 환경을 사용하려면 작업을 만들기 전에 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#the-cloud-environment">환경을 생성</a>하세요.</p><p><strong>5단계: 예약 선택</strong></p><p><a href="#빈도-옵션">빈도 옵션</a>에서 작업 실행 빈도를 선택하세요. 기본값은 현지 시간대 기준 매일 오전 9시입니다. 지연을 분산시키기 위해 작업은 예약된 시간에서 몇 분 후에 실행될 수 있습니다.</p><p>사전 설정 옵션이 맞지 않으면 가장 가까운 옵션을 선택한 후 CLI에서 <code>/schedule update</code>로 예약을 업데이트해 특정 일정을 설정하세요.</p><p><strong>6단계: 커넥터 검토</strong></p><p>연결된 모든 <a href="/claude-code-docs-ko/mcp.html">MCP 커넥터</a>가 기본으로 포함됩니다. 작업에 필요하지 않은 커넥터는 제거하세요. 커넥터를 통해 Claude는 각 실행 중 Slack, Linear, Google Drive 같은 외부 서비스에 접근할 수 있습니다.</p><p><strong>7단계: 작업 생성</strong></p><p><strong>Create</strong>를 클릭하세요. 작업이 예약된 작업 목록에 나타나고 다음 예약 시간에 자동으로 실행됩니다. 각 실행은 다른 세션과 함께 새 세션을 생성하며, Claude가 무엇을 했는지 확인하고, 변경 사항을 검토하고, 풀 리퀘스트를 생성할 수 있습니다. 즉시 실행을 트리거하려면 작업 상세 페이지에서 <strong>Run now</strong>를 클릭하세요.</p><h3 id="빈도-옵션" tabindex="-1">빈도 옵션 <a class="header-anchor" href="#빈도-옵션" aria-label="Permalink to &quot;빈도 옵션&quot;">​</a></h3><p>예약 선택기는 시간대 변환을 자동으로 처리하는 사전 설정 빈도를 제공합니다. 현지 시간대로 시간을 선택하면 클라우드 인프라가 어디에 위치하든 해당 시각에 작업이 실행됩니다.</p><p>:::note 작업은 예약된 시간에서 몇 분 후에 실행될 수 있습니다. 오프셋은 각 작업에 대해 일관적입니다. :::</p><table tabindex="0"><thead><tr><th style="text-align:left;">빈도</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">Hourly</td><td style="text-align:left;">매 시간마다 실행됩니다.</td></tr><tr><td style="text-align:left;">Daily</td><td style="text-align:left;">지정한 시간에 하루 한 번 실행됩니다. 기본값은 현지 시간 오전 9시입니다.</td></tr><tr><td style="text-align:left;">Weekdays</td><td style="text-align:left;">Daily와 동일하지만 토요일과 일요일은 건너뜁니다.</td></tr><tr><td style="text-align:left;">Weekly</td><td style="text-align:left;">지정한 요일과 시간에 주 1회 실행됩니다.</td></tr></tbody></table><p>2시간마다 또는 매월 1일 같은 커스텀 간격의 경우 가장 가까운 사전 설정을 선택하고 CLI에서 <code>/schedule update</code>로 예약을 업데이트해 특정 cron 표현식을 설정하세요. 최소 간격은 1시간입니다. <code>*/30 * * * *</code>처럼 더 자주 실행되는 표현식은 거부됩니다.</p><h3 id="저장소-및-브랜치-권한" tabindex="-1">저장소 및 브랜치 권한 <a class="header-anchor" href="#저장소-및-브랜치-권한" aria-label="Permalink to &quot;저장소 및 브랜치 권한&quot;">​</a></h3><p>예약된 작업이 저장소를 클론하려면 GitHub 접근 권한이 필요합니다. CLI에서 <code>/schedule</code>로 작업을 만들 때 Claude는 계정에 GitHub가 연결되어 있는지 확인하고, 연결되어 있지 않으면 <code>/web-setup</code>을 실행하도록 안내합니다. 접근 권한을 부여하는 두 가지 방법은 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#github-authentication-options">GitHub 인증 옵션</a>을 참고하세요.</p><p>추가한 각 저장소는 실행마다 클론됩니다. 프롬프트에서 별도로 지정하지 않으면 Claude는 저장소의 기본 브랜치에서 시작합니다.</p><p>기본적으로 Claude는 <code>claude/</code> 접두사가 붙은 브랜치에만 푸시할 수 있습니다. 이는 예약된 작업이 보호된 브랜치나 장기 브랜치를 실수로 수정하는 것을 방지합니다.</p><p>특정 저장소에 대해 이 제한을 해제하려면 작업을 만들거나 편집할 때 해당 저장소에서 <strong>Allow unrestricted branch pushes</strong>를 활성화하세요.</p><h3 id="커넥터" tabindex="-1">커넥터 <a class="header-anchor" href="#커넥터" aria-label="Permalink to &quot;커넥터&quot;">​</a></h3><p>예약된 작업은 연결된 MCP 커넥터를 사용해 각 실행 중 외부 서비스를 읽고 쓸 수 있습니다. 예를 들어 지원 요청을 분류하는 작업은 Slack 채널을 읽고 Linear에 이슈를 생성할 수 있습니다.</p><p>작업을 만들 때 현재 연결된 모든 커넥터가 기본으로 포함됩니다. 실행 중 Claude가 접근하는 도구를 제한하기 위해 필요하지 않은 커넥터는 제거하세요. 작업 양식에서 직접 커넥터를 추가할 수도 있습니다.</p><p>작업 양식 외부에서 커넥터를 관리하거나 추가하려면 claude.ai의 <strong>Settings &gt; Connectors</strong>를 방문하거나 CLI에서 <code>/schedule update</code>를 사용하세요.</p><h3 id="환경" tabindex="-1">환경 <a class="header-anchor" href="#환경" aria-label="Permalink to &quot;환경&quot;">​</a></h3><p>각 작업은 네트워크 접근, 환경 변수, 설정 스크립트를 제어하는 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#the-cloud-environment">클라우드 환경</a>에서 실행됩니다. Claude가 API에 접근하고, 의존성을 설치하고, 네트워크 범위를 제한할 수 있도록 작업을 만들기 전에 환경을 설정하세요. 전체 설정 가이드는 <a href="/claude-code-docs-ko/claude-code-on-the-web.html#the-cloud-environment">클라우드 환경</a>을 참고하세요.</p><h2 id="예약된-작업-관리" tabindex="-1">예약된 작업 관리 <a class="header-anchor" href="#예약된-작업-관리" aria-label="Permalink to &quot;예약된 작업 관리&quot;">​</a></h2><p><strong>Scheduled</strong> 목록에서 작업을 클릭하면 상세 페이지가 열립니다. 상세 페이지에는 작업의 저장소, 커넥터, 프롬프트, 예약, 그리고 지난 실행 목록이 표시됩니다.</p><h3 id="실행-보기-및-상호작용" tabindex="-1">실행 보기 및 상호작용 <a class="header-anchor" href="#실행-보기-및-상호작용" aria-label="Permalink to &quot;실행 보기 및 상호작용&quot;">​</a></h3><p>실행 항목을 클릭하면 전체 세션으로 열립니다. 여기서 Claude가 무엇을 했는지 확인하고, 변경 사항을 검토하고, 풀 리퀘스트를 생성하거나, 대화를 계속할 수 있습니다. 각 실행 세션은 다른 세션과 동일하게 작동합니다. 세션 제목 옆의 드롭다운 메뉴를 사용해 이름 변경, 보관, 삭제가 가능합니다.</p><h3 id="작업-편집-및-제어" tabindex="-1">작업 편집 및 제어 <a class="header-anchor" href="#작업-편집-및-제어" aria-label="Permalink to &quot;작업 편집 및 제어&quot;">​</a></h3><p>작업 상세 페이지에서 다음을 수행할 수 있습니다:</p><ul><li><strong>Run now</strong>를 클릭해 다음 예약 시간을 기다리지 않고 즉시 실행을 시작합니다.</li><li><strong>Repeats</strong> 섹션의 토글을 사용해 예약을 일시 중지하거나 재개합니다. 일시 중지된 작업은 설정을 유지하지만 다시 활성화할 때까지 실행되지 않습니다.</li><li>편집 아이콘을 클릭해 이름, 프롬프트, 예약, 저장소, 환경, 또는 커넥터를 변경합니다.</li><li>삭제 아이콘을 클릭해 작업을 제거합니다. 작업이 생성한 지난 세션은 세션 목록에 남아 있습니다.</li></ul><p>CLI에서 <code>/schedule</code>로도 작업을 관리할 수 있습니다. <code>/schedule list</code>로 모든 작업 목록 보기, <code>/schedule update</code>로 작업 변경, <code>/schedule run</code>으로 즉시 실행 트리거가 가능합니다.</p><h2 id="관련-자료" tabindex="-1">관련 자료 <a class="header-anchor" href="#관련-자료" aria-label="Permalink to &quot;관련 자료&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">데스크탑 예약 작업</a>: 로컬 파일에 접근하며 내 컴퓨터에서 실행되는 작업 예약. 데스크탑 앱의 <strong>Schedule</strong> 페이지에서 로컬 및 원격 작업을 같은 그리드에서 볼 수 있습니다.</li><li><a href="/claude-code-docs-ko/scheduled-tasks.html"><code>/loop</code> 및 CLI 예약 작업</a>: CLI 세션 내 경량 예약</li><li><a href="/claude-code-docs-ko/claude-code-on-the-web.html#the-cloud-environment">클라우드 환경</a>: 클라우드 작업의 런타임 환경 설정</li><li><a href="/claude-code-docs-ko/mcp.html">MCP 커넥터</a>: Slack, Linear, Google Drive 같은 외부 서비스 연결</li><li><a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a>: 저장소 이벤트에 따라 CI 파이프라인에서 Claude 실행</li></ul>',58)])])}const p=e(o,[["render",s]]);export{g as __pageData,p as default};
